#!/bin/bash
# === DEPLOY dashboard.html — Prismatic Labs ===
# Gerado automaticamente — sem duplicação, checksum verificado

TARGET="/root/projetos/prismatic-labs-hq/vendedor-ai/public/dashboard.html"
TMP="/tmp/_dash_deploy.b64"

echo "[1/4] Limpando arquivo temporário..."
rm -f "$TMP"
printf '%s' '' >> "$TMP"
echo "[1/4] Chunk OK"
printf '%s' '' >> "$TMP"
echo "[2/4] Chunk OK"
printf '%s' '' >> "$TMP"
echo "[3/4] Chunk OK"
printf '%s' '' >> "$TMP"
echo "[4/4] Chunk OK"

echo "[deploying] Decodificando e descomprimindo..."
base64 -d "$TMP" | gunzip > "$TARGET"
LINES=$(wc -l < "$TARGET")
echo "[OK] dashboard.html → $LINES linhas"
rm -f "$TMP"
